/**
 * canonical-ingredients.ts — generated, do not edit by hand.
 *
 * Built from the existing recipe corpus: every ingredient name normalised
 * via INGREDIENT_SYNONYMS, deduped, with the most-common unit and median
 * amount captured as smart defaults for the Add Recipe autocomplete.
 *
 * Smart-default rule (per Patrick, sign-off 2026-04-25):
 *   - Always default to the most common amount in metric units.
 *     Predictable beats clever.
 *
 * Regenerate via the Python script in tools/build-canonical-ingredients.py.
 */

export type CanonicalIngredient = {
  /** Normalised key — matches normalizeForMatch() output. */
  canonical: string;
  /** Display name in title-case-ish form. */
  name: string;
  /** Median amount across recipes that use this ingredient. */
  default_amount: number;
  /** Most common unit across recipes. Empty string for unitless. */
  default_unit: string;
  /** How many recipes use this ingredient — drives autocomplete ranking. */
  recipe_count: number;
  /** Surface forms that should match this canonical entry. */
  aliases: string[];
};

